INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 24001, 125801, 1, "リリ", 2, 1, 321);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, 24001, 126001, 1, "クリア", 2, 1, 322);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "んーと。\nこれ、あげる。\nはい", 3, 24001, 126101, 1, "プレシア", 2, 1, 323);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 4, 24001, 125801, 1, "リリ", 2, 2, 324);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 5, 24001, 126001, 1, "クリア", 2, 2, 325);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (40011, 0, "お兄。\nきてくれて、うれしい", 6, 24001, 126101, 1, "プレシア", 2, 2, 326);
